/* eslint-disable consistent-return */
import React from 'react';
import { type Control } from '@teambit/compositions.ui.composition-live-controls';

const DEFAULT_CONTROLS_REQUEST =
  'composition-live-controls:request-default-controls';
const DEFAULT_CONTROLS_RESPONSE = 'composition-live-controls:default-controls';

type DefaultControlsRequestPayload = {
  id: string;
  name: string;
};

type DefaultControlsResponsePayload = {
  id: string;
  name: string;
  controls?: Control[];
  schema?: any;
};

function getCompositionHref() {
  const { hash } = window.location;
  const componentId = hash.split('?')[0].slice(1);
  const params = hash
    .split('?')[1]
    .split('&')
    .map((x) => x.split('='))
    .reduce(
      (acc, [key, value]) => {
        acc[key] = value;
        return acc;
      },
      {} as Record<string, string>
    );
  if (params.preview === 'compositions' && params.livecontrols) {
    return JSON.stringify({
      id: componentId,
      name: params.name,
    });
  }
  return null;
}

export function getDefaultControlsHook(
  defaultControlsParser: (schema: any) => Record<string, Control[]>
) {
  return function useDefaultControls(enabled?: boolean): Control[] {
    const [defaultControls, setDefaultControls] = React.useState<Control[]>([]);
    const currentHref = getCompositionHref();

    React.useEffect(() => {
      if (!currentHref) return;
      if (!enabled) return;
      const { id, name } = JSON.parse(currentHref);
      function requestDefaultControls() {
        if (!window.parent || window.parent === window) return;
        window.parent.postMessage(
          {
            type: DEFAULT_CONTROLS_REQUEST,
            payload: { id, name } satisfies DefaultControlsRequestPayload,
          },
          '*'
        );
      }

      function onMessage(event: MessageEvent) {
        if (event.source !== window.parent) return;
        const { data } = event;
        if (!data?.type || data.type !== DEFAULT_CONTROLS_RESPONSE) return;
        const payload = data.payload as
          | DefaultControlsResponsePayload
          | undefined;
        if (!payload) return;
        if (payload.id !== id || payload.name !== name) return;
        if (Array.isArray(payload.controls)) {
          setDefaultControls(payload.controls);
          return;
        }

        if (payload.schema) {
          const schema = defaultControlsParser(payload.schema);
          if (schema[name]) {
            setDefaultControls(schema[name]);
          }
        }
      }

      window.addEventListener('message', onMessage);

      function reset() {
        requestDefaultControls();
      }
      // webpack hmr manual integration
      // @ts-ignore
      if (typeof module !== 'undefined') {
        // @ts-ignore
        const webpackHot = (module as any)?.hot;
        if (webpackHot?.addStatusHandler) {
          webpackHot.addStatusHandler((status: string) => {
            // React to the current status...
            if (status === 'ready') {
              reset();
            }
          });
        }
      }
      // Vite hmr manual integration
      if ((import.meta as any).hot) {
        // Also listen to Vite-specific afterUpdate event (if available)
        (import.meta as any).hot.on?.('vite:afterUpdate', reset);
      }
      reset();
      return () => {
        window.removeEventListener('message', onMessage);
      };
    }, [enabled, currentHref]);

    return defaultControls;
  };
}
